	import org.apache.commons.logging.Log;
	import org.apache.commons.logging.LogFactory;
	import sailpoint.object.AttributeDefinition;
	import sailpoint.object.AttributeSource;
	import sailpoint.object.AttributeTarget;
	import sailpoint.object.Identity;
	import sailpoint.tools.Util;
	import sailpoint.object.Link;

	Log logger = LogFactory.getLog("rule.identityattributetarget.ignoredisableaccount");
	logger.debug("Starting of rule Ascension-Rule-IdentityAttributeTarget-IgnoreDisableAccount");
	
	public Object getAttributeValue(String application, Link link, String targetAttName, String sourceIdentityAttributeName, Identity identity, Object value){
		if(null != link && link.isDisabled()){
			logger.debug("Picking value from disabled Link");
			value = link.getAttribute(targetAttName);
		}else if(null != identity){
			logger.debug("Picking value from identity attribute");
			value = identity.getAttribute(sourceIdentityAttributeName);
		}
		return value;
	}
	
	logger.debug("identity processed " + identity.getName());
	logger.debug("Entering Ascension-Rule-IdentityAttributeTarget-IgnoreDisableAccount..." + value);
	String appname = null != link ? link.getApplicationName():"";
	String targetAttName = target.getName();
	logger.debug("AppName is " + appname + " TargetAttName is " + targetAttName + " sourceIdentityAttributeName " + sourceIdentityAttributeName);
	value = getAttributeValue(appname, link, targetAttName, sourceIdentityAttributeName, identity, value);
	logger.debug("Exiting of rule Ascension-Rule-IdentityAttributeTarget-IgnoreDisableAccount " + value);
	return value;
